        if current_max < best_max_kvpr:
            best_max_kvpr = current_max
            best_assignment = [lst[:] for lst in assignment]

    if best_assignment is None:
        return {i: [] for i in range(gpu_num)}

    return {i: best_assignment[i] for i in range(gpu_num)}

def compute_model_placement(gpu_num, models):
    GPU_MEM_SIZE = 80

    # Precompute model characteristics
    model_data = []
    for model in models:
        weighted_req = model.req_rate / model.slo
        model_data.append((model, weighted_req, model.model_size))

    # Sort by weighted_req descending (priority to high-demand models)
    model_data.sort(key=lambda x: x[1], reverse=True)

    # Initialize GPU states
    gpu_memory = [GPU_MEM_SIZE] * gpu_num
    gpu_weighted_req = [0.0] * gpu_num
    assignment = [[] for _ in range(gpu_num)]

    # Greedy assignment
    for model, weighted_req, model_size in model_data:
        best_gpu = -1
        min_max_kvpr = float('inf')

        # Try all GPUs that can fit this model
        for gpu_id in range(gpu_num):
            if gpu_memory[gpu_id] >= model_size:
                # Simulate adding model to this GPU
                new_weighted_req = gpu_weighted_req[gpu_id] + weighted_req
                new_memory_free = gpu_memory[gpu_id] - model_size

                # Calculate KVPR for this GPU after assignment
                if new_memory_free > 0:
                    new_kvpr = new_weighted_req / new_memory_free
                else:
                    new_kvpr = float('inf')

                # Calculate what the new max KVPR would be
                current_max_kvpr = 0.0
                valid_gpus = 0

                # Find max KVPR across all GPUs
                for i in range(gpu_num):
                    if gpu_memory[i] < GPU_MEM_SIZE:  # Not full
                        valid_gpus += 1
                        if i == gpu_id:
                            if new_memory_free > 0:
                                current_max_kvpr = max(current_max_kvpr, new_kvpr)
                            else:
                                current_max_kvpr = float('inf')
                                break
                        else:
                            if gpu_memory[i] - gpu_weighted_req[i] > 0:
                                current_max_kvpr = max(current_max_kvpr, gpu_weighted_req[i] / (gpu_memory[i] - gpu_weighted_req[i]))
                            else:
                                current_max_kvpr = float('inf')
                                break
                    elif gpu_memory[i] == GPU_MEM_SIZE:  # Full GPU
                        if i == gpu_id:
                            current_max_kvpr = max(current_max_kvpr, new_kvpr)
                        else:
                            current_max_kvpr = max(current_max_kvpr, 0.0)  # Shouldn't happen
                    else:
                        # This should not happen with correct logic
                        pass

                # If all GPUs are valid, update best GPU
                if valid_gpus == gpu_num or (valid_gpus > 0 and current_max_kvpr < float('inf')):
                    if current_max_kvpr < min_max_kvpr:
                        min_max_kvpr = current_max_kvpr
                        best_gpu = gpu_id

        # If no good GPU found, assign to one with most free memory
        if best_gpu == -1:
            best_gpu = max(range(gpu_num), key=lambda i: gpu_memory[i])

        # Assign model
        assignment[best_gpu].append(model)
        gpu_memory[best_gpu] -= model_size
        gpu_weighted_req[best_gpu] += weighted_req

    # Convert to dictionary format
    return {i: assignment[i] for i in range(gpu_num)}
